INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2039712148664057857, 2039344298904473602, 'assistant', '你好！我是**健小助**，很高兴为你服务！💪

作为你的专业智能健身助手，我可以为你提供科学的训练指导、营养饮食建议、器械使用方法、个性化训练计划制定以及运动损伤预防等方面的帮助。

请问今天有什么健身方面的问题想要咨询吗？无论是想增肌、减脂还是改善体态，随时都可以告诉我！', '2026-04-02 22:30:46.923728');
INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2039751048342241281, 2039344298904473602, 'assistant', '您好！我是健小助。

关于具体的健身房位置，因为我无法获取您所在场馆的实时定位信息，建议您可以通过以下方式查询：

1.  **查看官方渠道**：请查看您办理会员时的协议、健身房的微信公众号或官方APP，通常在“联系我们”或“场馆介绍”中会有详细的地址地图。
2.  **导航软件搜索**：直接在地图导航软件中搜索健身房的具体名称，即可获得准确的定位和路线规划。
