INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2039758468971974658, 2039344298904473602, 'assistant', '您好！我是健小助。关于停卡（冻结）的办理流程和规则，为您解答如下：

**办理方式：**
