INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2040429557269258241, 2040136544634544130, 'assistant', '您好！我是您的智能健身助手“健小助”。

关于您询问的**具体地址**和**交通路线**，因为我是一款线上的智能助手，无法获取您当前所在的具体健身房或场馆的地理位置信息。

