INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2039753805950320642, 2039344298904473602, 'assistant', '您好！我是力健空间健身中心的智能健身助手“健小助”。关于如何增肌，结合我们场馆的服务内容，为您提供以下建议：

