INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2040084875216363521, 2039944885920542721, 'assistant', '您好！我是“健小助”，很高兴为您介绍力健空间健身中心的合作项目。我们主要提供以下两类合作机会：

### 一、 企业团办合作
针对企业客户，我们提供灵活的团购优惠与定制服务：

1.  **团购优惠**：
    *   10人以上团办，可享受 **8折** 优惠。
    *   20人以上团办，可享受 **7.5折** 优惠。
    *   50人以上团办，可享受 **7折** 优惠，还可定制专属企业课程。

2.  **合作方式**：
    *   企业统一为员工办卡，费用由企业统一支付。
    *   企业发放健身补贴，员工自行办卡，同样可享受团办优惠。

3.  **定制服务**：
    *   可安排教练上门为企业做健康讲座、体测服务。
    *   可定制企业专属的团课、团建活动。

4.  **咨询方式**：请联系我们的商务经理 **138-XXXX-XXXX**。

### 二、 异业合作
我们也欢迎各类异业商家合作，资源互换，互利共赢：

1.  **合作类型**：周边餐饮、美容美发、瑜伽馆、体检中心等。
2.  **合作方式**：互相引流、联合活动、会员权益互通等。
3.  **咨询方式**：请致电 **400-888-9999** 转商务合作。

如果您对以上合作感兴趣，欢迎拨打对应的咨询电话进行详细了解！', '2026-04-03 23:11:51.857771');
INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2040447518247870465, 2040136544634544130, 'assistant', '你好！我是**健小助**，你的专业智能健身助手。我可以为你提供全方位的健身支持，具体包括以下几个方面：

1.  **🏋️ 健身训练指导**
    无论是力量训练（如深蹲、卧推）、有氧运动，还是柔韧性训练，我都能为你提供标准的动作讲解和技巧指导，帮你科学锻炼。

2.  **🥗 营养饮食建议**
    我可以帮你制定增肌或减脂的饮食策略，解答关于蛋白质摄入、运动补剂（如蛋白粉、肌酸）的使用疑问，助你“三分练，七分吃”。

3.  **🛠️ 器械使用指导**
    不熟悉健身房的各种器械？我会教你各种固定器械和自由重量的正确使用方法，以及注意事项，让你练得更安全、更高效。

4.  **📅 训练计划制定**
    根据你的健身目标（增肌、减脂、塑形等）和实际情况，为你量身定制个性化的训练计划。

5.  **🛡️ 运动损伤预防**
    教你如何进行正确的热身和拉伸，规避常见的运动损伤风险。如果你在运动中有不适感，我也会提供相应的建议。

6.  **🏢 健身房相关信息**
    为你解答关于健身房的营业时间、场馆设施、会员政策及课程安排等问题。

**我的回答原则是：专业准确、简洁明了、安全第一。**

请告诉我，你今天想了解哪方面的内容？或者你目前的健身目标是什么？我随时准备为你服务！', '2026-04-04 23:12:52.688411');
INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2040845709204074498, 2040845309902139394, 'assistant', '您好！我是“力健空间健身中心”的智能健身助手“健小助”。

制定一份完全个性化的健身训练计划通常需要了解您的身体状况、健身基础和具体目标（如减脂、增肌或康复）。由于目前缺乏您的个人身体数据，我无法为您直接生成专属方案。

