INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2041179812252209154, 2040851441290915842, 'assistant', '根据我的功能，我主要提供健身相关的服务和指导。如果你是在询问健身房的营业时间，这通常因具体健身房而异。一般来说，健身房在工作日的营业时间是从早上7:00到晚上10:00不等，周末时间可能会更长一些。

