INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2041196586137870337, 2040851441290915842, 'assistant', '根据知识库内容，力健空间健身中心提供丰富的团操课程和一对一私教服务。以下是课程安排和私教内容的概览：

### 团课课程安排（每周更新，具体以公众号当日发布为准）
- **09:00-10:00**：瑜伽、动感单车、普拉提、有氧操、瑜伽、搏击操、核心训练
- **10:30-11:30**：普拉提、核心训练、动感单车、舞蹈、普拉提、瑜伽、动感单车
- **14:00-15:00**：有氧操、瑜伽、搏击操、核心训练、有氧操、舞蹈、普拉提
- **15:30-16:30**：动感单车、普拉提、瑜伽、动感单车、搏击操、有氧操、瑜伽
- **19:00-20:00**：搏击操、动感单车、舞蹈、瑜伽、动感单车、核心训练（周六无课）
- **20:30-21:30**：核心训练、有氧操、瑜伽、普拉提、瑜伽（周日无课）

### 私教服务
- **减脂塑形**：定制饮食 + 训练计划，高效燃脂
- **增肌增重**：制定力量训练计划，科学增肌
- **体态调整**：改善圆肩、驼背、骨盆前倾等不良体态
- **康复训练**：针对肩颈腰腿痛、运动损伤后的康复训练
- **产后恢复**：针对产后妈妈的盆底肌修复、腹直肌分离修复
- **儿童体适能**：针对儿童的体能训练，提升免疫力与运动能力

如需预约团课或私教课程，可关注“力健空间健身中心”公众号，进入会员中心 - 课程预约，选择您想要的课程进行预约。', '2026-04-07 00:49:24.390827');
INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2041196664789458946, 2040851441290915842, 'user', '有哪些教练', '2026-04-07 00:49:43.141047');
INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2041196688067846145, 2040851441290915842, 'assistant', '根据知识库信息，我们有以下教练：

