INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2041381172402782210, 2040851441290915842, 'user', '有什么类型的卡', '2026-04-07 13:02:53.178086');
INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2041381250362310657, 2040851441290915842, 'assistant', '我来帮你分析一下你提到的"有什么类型的卡"。在健身相关的语境中，"卡"通常指的是健身房的会员卡或各类健身相关卡券。以下是常见的几种类型：

1. **健身会员卡**：
   - **月卡/季卡/年卡**：按时间长度收费，适合不同健身频率的用户
   - **无限次卡**：在有效期内可无限次使用健身房设施
   - **有限次卡**：在有效期内有固定的使用次数或时段

2. **私教课程卡**：
   - **按次收费**：每次私教课程单独收费
   - **包月/包季/包年**：按时间段购买私教课程的套餐
   - **定制计划卡**：根据个人目标定制专属训练计划

3. **体测卡**：
   - **基础体测**：包括身高、体重、体脂、腰围等基础测量
   - **专业体测**：包括心肺功能、身体成分分析等专业测试

4. **运动营养卡**：
   - **营养咨询**：提供专业的营养师咨询服务
   - **补剂代购**：提供运动补剂的购买服务

5. **课程卡**：
   - **瑜伽/普拉提课程**：提供各类瑜伽和普拉提课程
   - **有氧课程**：如HIIT、跑步、游泳等有氧运动课程

6. **健康监测卡**：
   - **智能设备监测**：连接智能手表或心率监测器进行健康监测
   - **定期体检**：提供定期的健康体检服务

在选择健身卡时，建议根据你的健身目标、时间安排和预算来选择最合适的类型。如果你有具体的健身目标和时间安排，我可以帮你制定一个个性化的健身计划。

如果你指的是其他类型的"卡"，请提供更多的背景信息，我会尽力提供更准确的建议。', '2026-04-07 13:03:11.78262');
INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2041383737865613313, 2040851441290915842, 'user', '有哪些教练', '2026-04-07 13:13:04.834909');
