INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2041428129544523778, 2040851441290915842, 'user', '怎么预约？', '2026-04-07 16:09:28.637583');
INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2041428171005218818, 2040851441290915842, 'assistant', '用户想了解如何预约课程。

根据知识库内容，预约团课的步骤如下：
1. 关注健身房的公众号
2. 进入“会员中心”-“课程预约”
3. 选择想要的课程进行预约

团课需提前24小时开放预约。如果临时有事需要取消，团课需提前2小时取消，否则会记为爽约。

如果您指的是私教课的预约，流程类似，但私教需提前24小时取消，否则会扣除1节课时；临时取消（不足24小时）会扣除半节课时。

请根据您实际想预约的课程类型，按上述步骤进行操作。', '2026-04-07 16:09:38.528935');
INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2041428356565422081, 2040851441290915842, 'user', '私教课有哪些服务？', '2026-04-07 16:10:22.775514');
INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2041428377671159809, 2040851441290915842, 'assistant', '根据知识库内容，我们私教提供一对一的定制化训练服务，包括：

- 减脂塑形：针对减脂需求，定制饮食 + 训练计划，高效燃脂
- 增肌增重：针对瘦体重提升，制定力量训练计划，科学增肌
- 体态调整：改善圆肩、驼背、骨盆前倾等不良体态
- 康复训练：针对肩颈腰腿痛、运动损伤后的康复训练
- 产后恢复：针对产后妈妈的盆底肌修复、腹直肌分离修复
- 儿童体适能：针对儿童的体能训练，提升免疫力与运动能力

私教收费标准如下：
- 12 节：280 元/节，总价 3360 元，有效期 90 天
- 24 节：260 元/节，总价 6240 元，有效期 180 天
- 36 节：240 元/节，总价 8640 元，有效期 270 天
- 48 节：220 元/节，总价 10560 元，有效期 365 天

注：私教课程可根据教练资质略有浮动，详情可咨询前台。', '2026-04-07 16:10:27.812085');
