INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2052407418037121026, 2052406882982342658, 'assistant', '您好！我是力健空间健身中心的智能健身助手“健小助”。我们为您提供了丰富的**团课**和**私教**课程，具体如下：

