INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2054840603685597185, 2040851441290915842, 'user', '请为我提供个性化的营养指导建议，包括每日饮食搭配、营养素摄入建议和饮食注意事项。', '2026-05-14 16:25:51.680271');
INSERT INTO public.chat_message (id, session_id, role, content, created_at) VALUES (2054840842626707457, 2040851441290915842, 'assistant', '根据您的档案（男，24岁，170cm，63kg，目标：健康养生），以下是为您定制的营养建议：

**每日饮食搭配**
- 早餐：全麦面包+鸡蛋1-2个+牛奶/豆浆+水果
- 午餐：杂粮饭+瘦肉/鱼+蔬菜2种+豆制品
- 晚餐：轻碳水（红薯/玉米）+清蒸鱼/鸡胸+绿叶菜

**营养素摄入建议**
- 蛋白质：约63g/天（1g/kg体重），鸡蛋、鱼肉、豆制品为主
- 碳水：占总热量50%，以粗粮为主，减少精制糖
- 脂肪：占总热量25%，优选坚果、橄榄油
- 每日热量：约1800-2000kcal，维持健康体重

**注意事项**
- 饮水充足，每日2000ml以上
- 少油少盐，避免油炸和加工食品
- 训练前后适当补充碳水+蛋白质
- 晚餐不宜过晚，睡前2小时不进食

更精准的饮食方案可咨询张磊教练（国家健身营养师），他能为您定制个性化饮食与训练计划。', '2026-05-14 16:26:48.645686');
