INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (98, '搏击体能强化', '专为搏击运动设计的体能训练，提升爆发力与耐力', 4, '拳击格斗', '14:56:29.588186', '15:56:29.588186', 15, 1, 'https://images.unsplash.com/photo-1549719386-74dfcbf7dbed?w=800', true, '2026-03-26 01:56:29.588186', '2026-04-02 18:09:12.791504', '高级', 60, 500, 750, 8, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (90, '普拉提核心床', '借助核心床进行普拉提训练，是强化核心肌群的高效途径。通过器械独特的弹簧阻力与滑动床板设计，训练者能在动态不稳定中精准激活深层肌群。这不仅有助于塑造紧致身形，更能显著提升身体稳定性与协调性，让每一次伸展与发力都充满控制之美。', 4, '瑜伽普拉提', '12:56:29', '13:56:29', 12, 1, 'https://images.unsplash.com/photo-1518310383802-640c2de311b2?w=800', true, '2026-03-26 01:56:29.585409', '2026-05-09 20:53:54.519395', '中级', 60, 250, 400, 8, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (84, '跳绳燃脂课', '高强度跳绳训练，快速提升心率，高效燃烧卡路里。', 3, '有氧燃脂', '09:56:29', '10:41:29', 20, 1, 'http://localhost:9000/fitness-bucket/courses/41873e51-e76b-44ae-9cad-9bc787845fb3.webp', true, '2026-03-26 01:56:29.583345', '2026-05-09 20:54:22.257405', '中级', 45, 350, 500, 12, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (86, '阶梯踏板训练', '利用踏板进行有氧训练，锻炼心肺功能与腿部力量', 3, '有氧燃脂', '19:56:29.583345', '20:56:29.583345', 24, 1, 'https://images.unsplash.com/photo-1518310383802-640c2de311b2?w=800', true, '2026-03-26 01:56:29.583345', '2026-05-09 20:54:55.250113', '初级', 50, 300, 450, 16, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (88, '有氧舞蹈派对', '结合流行舞蹈的有氧运动，快乐燃脂不枯燥', 3, '有氧燃脂', '20:56:29.583345', '21:56:29.583345', 30, 1, 'https://images.unsplash.com/photo-1524594152303-9fd13543fe6e?w=800', true, '2026-03-26 01:56:29.583345', '2026-05-09 20:54:59.922054', '初级', 50, 350, 500, 25, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (85, '搏击有氧操', '结合拳击动作的有氧运动，燃脂解压，提升协调性', 4, '有氧燃脂', '20:56:29', '21:56:29', 28, 2, 'https://images.unsplash.com/photo-1549576490-b0b4831ef60a?w=800', true, '2026-03-26 01:56:29.583345', '2026-05-09 20:55:03.161167', '中级', 60, 450, 650, 20, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (80, '手臂力量轰炸', '二头肌与三头肌超级组训练，突破臂围瓶颈，高效刺激双臂肌群，提升力量与耐力。', 3, '力量训练', '10:56:29', '11:56:29', 20, 1, 'http://localhost:9000/fitness-bucket/courses/589bd94f-3ee4-4cd0-9896-528bcd2d2930.webp', true, '2026-03-26 01:56:29.577083', '2026-05-09 20:55:06.099373', '中级', 40, 250, 400, 15, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (79, '肩部塑形训练', '针对三角肌前中后束的专项训练，打造立体肩部，配备多角度固定式肩推与侧平举、高低坐姿推举等模块，多点位激活并塑形肩峰线，提供可调阻力与多档位选择，满足进阶塑形与力量提升需求。', 4, '力量训练', '17:56:29', '18:56:29', 18, 1, 'https://images.unsplash.com/photo-1583454110551-21f2fa2afe61?w=800', true, '2026-03-26 01:56:29.577083', '2026-05-09 20:55:08.559009', '中级', 45, 300, 450, 12, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (76, '杠铃深蹲特训', '系统掌握杠铃深蹲要领，强化下肢力量与核心稳定，提升运动表现与体态控制。', 3, '力量训练', '10:56:29', '11:56:29', 15, 1, 'https://images.unsplash.com/photo-1534367507873-d2d7e24c797f?w=800', true, '2026-03-26 01:56:29.577083', '2026-05-09 20:55:10.854485', '高级', 60, 400, 600, 8, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (81, '全身力量循环', '以复合动作为核心构建力量循环训练，系统提升全身整体力量水平。', 4, '力量训练', '16:56:29', '18:26:29', 16, 1, 'https://images.unsplash.com/photo-1534438327276-14e5300c3a48?w=800', true, '2026-03-26 01:56:29.577083', '2026-05-09 20:55:13.180699', '初级', 90, 500, 800, 10, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (77, '胸背超级组训练', '胸肌与背部肌群交替训练，打造完美上半身线条', 4, '力量训练', '15:56:29', '16:56:29', 12, 1, 'http://localhost:9000/fitness-bucket/courses/5f60ffe5-754b-4ad1-b974-94632893fc96.jpg', true, '2026-03-26 01:56:29.577083', '2026-05-09 20:55:15.749797', '中级', 50, 350, 550, 6, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (82, '燃脂动感单车', '高强度骑行训练，提供电动与手动双模式，心率与阻力可调，高强度间歇训练与节奏训练可选，提升心肺耐力与燃脂效率，适用于体能强化与耐力提升。', 3, '有氧燃脂', '19:56:29', '20:56:29', 25, 1, 'http://localhost:9000/fitness-bucket/courses/0da9ecfc-d9be-4659-85f6-9c072b1df915.webp', false, '2026-03-26 01:56:29.583345', '2026-05-29 00:58:54.553271', '中级', 45, 400, 600, 21, 5);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (103, '肩颈舒缓康复', '针对肩颈僵硬的康复训练，专为缓解办公室综合症量身打造。采用科学的肩颈放松与激活方案，结合颈部、肩部及上背部的渐进式拉伸与强化训练，促进血液循环、缓解肌肉紧张，有效改善由长时间伏案与久坐引发的肩颈僵硬与疼痛，提升工作舒适度与效率。', 3, '康复体态', '13:56:29', '14:56:29', 20, 1, 'https://images.unsplash.com/photo-1575052814086-f385e2e2ad1b?w=800', true, '2026-03-26 01:56:29.59211', '2026-04-07 16:16:31.864845', '初级', 45, 150, 250, 16, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (92, '空中瑜伽入门', '利用吊床进行的瑜伽练习，增强核心与柔韧性', 4, '瑜伽普拉提', '12:56:29.585409', '13:56:29.585409', 10, 1, 'https://images.unsplash.com/photo-1599901860904-17e6ed7083a0?w=800', true, '2026-03-26 01:56:29.585409', '2026-04-08 22:48:06.566039', '中级', 60, 200, 350, 6, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (95, '泰拳实战技巧', '学习泰拳基础动作，提升力量与反应速度。提供泰拳基础课程，系统训练踢、打、闪避等核心动作，结合力量与反应训练，强化实战应变与体能耐受，提升整体格斗能力与身体协调性。', 3, '拳击格斗', '14:56:29', '15:56:29', 12, 1, 'http://localhost:9000/fitness-bucket/courses/7ba89f77-3768-4df9-8c29-4ff4bd0e4a7d.webp', true, '2026-03-26 01:56:29.588186', '2026-05-09 20:53:48.754354', '中级', 60, 450, 700, 7, 4);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (96, '综合格斗训练', '融合拳击、踢拳、摔跤的综合格斗技术训练', 4, '拳击格斗', '14:56:29.588186', '15:56:29.588186', 10, 1, 'https://images.unsplash.com/photo-1555597673-b21d5c935865?w=800', true, '2026-03-26 01:56:29.588186', '2026-05-09 20:53:51.653938', '高级', 60, 500, 800, 5, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (93, '垫上普拉提塑形', '经典垫上普拉提动作，塑造修长线条与优雅体态', 3, '瑜伽普拉提', '11:56:29.585409', '12:56:29.585409', 16, 1, 'https://images.unsplash.com/photo-1575052814086-f385e2e2ad1b?w=800', true, '2026-03-26 01:56:29.585409', '2026-05-09 20:54:17.559982', '初级', 50, 180, 300, 10, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (97, '防身术实战', '实用的自我防卫技巧与情景模拟训练', 3, '拳击格斗', '15:56:29.588186', '16:56:29.588186', 20, 1, 'https://images.unsplash.com/photo-1555597673-b21d5c935865?w=800', true, '2026-03-26 01:56:29.588186', '2026-05-09 20:54:25.647635', '中级', 60, 350, 550, 12, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (105, '产后修复训练', '专为产后妈妈定制盆底肌与腹直肌科学修复方案。针对分娩造成的肌群损伤与松弛，采用精准训练深层激活盆底肌，强化腹直肌力量，有效改善漏尿、腹直肌分离及腰腹松弛问题。通过循序渐进的专业指导，帮助妈妈重塑核心稳定性，加速身体机能恢复，重拾紧致体态与自信风采。', 3, '康复体态', '15:56:29', '16:56:29', 12, 1, 'https://images.unsplash.com/photo-1518310383802-640c2de311b2?w=800', true, '2026-03-26 01:56:29.59211', '2026-05-09 20:55:23.966737', '初级', 45, 120, 200, 8, 2);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (104, '脊柱侧弯矫正', '借助科学系统的专业训练，针对性矫正脊柱侧弯问题。通过强化核心肌群与优化体态排列，有效改善脊柱生理曲度，帮助身体重获自然平衡与挺拔姿态，从而提升整体健康气质。', 4, '康复体态', '13:56:29', '14:56:29', 15, 1, 'https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=800', true, '2026-03-26 01:56:29.59211', '2026-05-09 20:55:27.335593', '中级', 50, 180, 300, 10, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (100, '爵士舞基础', '学习爵士舞基本动作与组合，提升身体协调性', 4, '舞蹈操课', '18:56:29.59005', '19:56:29.59005', 25, 1, 'https://images.unsplash.com/photo-1508700115892-45ecd05ae2ad?w=800', true, '2026-03-26 01:56:29.59005', '2026-05-09 20:55:31.887251', '初级', 60, 300, 450, 15, 1);
INSERT INTO public.fitness_course (id, course_name, description, coach_id, category, start_time, end_time, capacity, status, image_url, deleted, create_time, update_time, difficulty_level, duration_minutes, calories_min, calories_max, total_booking_count, day_of_week) VALUES (102, '民族健身操', '本套健身操创新融合了民族舞蹈的艺术精髓，将传统舞姿的柔美韵律与现代健身的科学节奏完美结合。在律动中，不仅能有效提升心肺功能、强健体魄，更能陶冶情操、展现优雅体态。它打破了传统健身的枯燥，实现了健康体魄与艺术修养的双重提升，让每一次跃动都成为一场身心合一的悦动体验。', 33, '舞蹈操课', '18:56:29', '19:56:29', 32, 1, 'http://localhost:9000/fitness-bucket/courses/cdce174a-912b-403a-8f12-e0b7977098da.jpg', true, '2026-03-26 01:56:29.59005', '2026-05-09 20:55:34.384386', '高级', 65, 300, 400, 20, 4);
