INSERT INTO public.fitness_equipment (id, equipment_name, location, status, description, image_url, purchase_date, deleted, create_time, update_time, type_code, equipment_no) VALUES (24, '龙门架综合训练器', '力量区-B02', 1, '这款双滑轮龙门架设计专业，支持多样化的拉力训练，全方位刺激目标肌群。配备80kg配重系统，阻力调节灵活精准，满足从基础塑形到力量进阶的不同需求。其运行平稳流畅，是打造家庭健身房或提升商业健身区专业度的理想选择。', 'http://localhost:9000/fitness-bucket/images/a29ba2e2-f49c-4340-b090-38a2ad3a3776.webp', '2024-01-12', false, '2026-03-28 11:27:11.898492', '2026-04-02 22:08:37.868785', 'STRENGTH', 'STRENGTH-002');
INSERT INTO public.fitness_equipment (id, equipment_name, location, status, description, image_url, purchase_date, deleted, create_time, update_time, type_code, equipment_no) VALUES (26, '蝴蝶机', '力量区-B04', 1, '双轴设计专为胸肌训练打造，动作轨迹更自然流畅，提升训练效率与舒适度。', 'http://localhost:9000/fitness-bucket/images/b2761133-ade2-4183-8da7-aa8854a3333b.webp', '2024-02-05', false, '2026-03-28 11:27:11.898492', '2026-04-06 17:11:35.450184', 'STRENGTH', 'STRENGTH-004');
