INSERT INTO public.fitness_equipment (id, equipment_name, location, status, description, image_url, purchase_date, deleted, create_time, update_time, type_code, equipment_no) VALUES (25, '腿举训练器', '力量区-B03', 1, '45度倒蹬机专为腿部力量训练设计，提供高效稳定、多角度的训练体验，通过倾斜角度调节实现从坐姿到站姿的平滑过渡，兼顾爆发力与耐力的提升。', 'http://localhost:9000/fitness-bucket/images/5255958d-f107-45a6-8383-6d4904961526.webp', '2024-01-25', false, '2026-03-28 11:27:11.898492', '2026-04-07 02:42:10.683452', 'STRENGTH', 'STRENGTH-003');
