INSERT INTO public.fitness_equipment (id, equipment_name, location, status, description, image_url, purchase_date, deleted, create_time, update_time, type_code, equipment_no) VALUES (18, '商用跑步机 X1', '有氧区-A01', 1, '这款高端商用跑步机专为专业健身打造，搭载15.6寸高清触控大屏，交互流畅灵敏。内置沉浸式虚拟场景跑步系统，让您在室内也能体验户外奔跑的乐趣。卓越的性能配置结合智能科技，不仅提升了运动趣味性，更为用户带来前所未有的专业健身体验。', 'http://localhost:9000/fitness-bucket/images/2a4e805e-b137-47c5-be32-e3b3e005e00a.webp', '2024-01-15', false, '2026-03-28 11:27:11.898492', '2026-04-13 00:59:56.651807', 'CARDIO', 'CARDIO-001');
