INSERT INTO public.fitness_plan (id, user_id, plan_name, goal, duration, status, deleted, create_time, update_time, level, height, weight, age, gender, experience, fitness_goal, plan_data_json) VALUES (59, 25, '7天增肌高级训练计划', NULL, NULL, 1, false, '2026-04-09 02:29:25.914813', '2026-04-09 02:29:25.914813', NULL, 170.00, 63.00, 24, 'MALE', '高级', '增肌', '{"subtitle": "7天增肌高级训练计划", "userInfo": {"bmi": "21.8", "goal": "增肌", "height": "170 cm", "weight": "63 kg", "intensity": "高级"}, "weeklyPlan": [{"focus": "全身复合动作强化", "courses": [{"id": 81, "name": "全身力量循环", "category": "力量训练", "duration": 90, "coverImage": "https://images.unsplash.com/photo-1534438327276-14e5300c3a48?w=800", "description": "以复合动作为核心构建力量循环训练，系统提升全身整体力量水平。"}, {"id": 76, "name": "杠铃深蹲特训", "category": "力量训练", "duration": 60, "coverImage": "https://images.unsplash.com/photo-1534367507873-d2d7e24c797f?w=800", "description": "系统掌握杠铃深蹲要领，强化下肢力量与核心稳定，提升运动表现与体态控制。"}], "dayName": "周一", "equipment": [{"name": "奥林匹克杠铃杆", "image": "http://localhost:9000/fitness-bucket/images/89f93cc1-0835-4764-9680-fe7e28a83c46.webp"}, {"name": "可调节哑铃套装", "image": "http://localhost:9000/fitness-bucket/images/960bcc89-c268-4913-985d-edd725ac7e7e.jpg"}], "exercises": [{"name": "杠铃深蹲", "reps": 4, "sets": 3, "restSeconds": 90}, {"name": "硬拉", "reps": 3, "sets": 3, "restSeconds": 120}, {"name": "推举", "reps": 3, "sets": 3, "restSeconds": 90}]}, {"focus": "上肢力量与肩部塑形", "courses": [{"id": 79, "name": "肩部塑形训练", "category": "力量训练", "duration": 45, "coverImage": "https://images.unsplash.com/photo-1583454110551-21f2fa2afe61?w=800", "description": "针对三角肌前中后束的专项训练，打造立体肩部，配备多角度固定式肩推与侧平举、高低坐姿推举等模块，多点位激活并塑形肩峰线，提供可调阻力与多档位选择，满足进阶塑形与力量提升需求。"}, {"id": 80, "name": "手臂力量轰炸", "category": "力量训练", "duration": 40, "coverImage": "http://localhost:9000/fitness-bucket/courses/589bd94f-3ee4-4cd0-9896-528bcd2d2930.webp", "description": "二头肌与三头肌超级组训练，突破臂围瓶颈，高效刺激双臂肌群，提升力量与耐力。"}], "dayName": "周二", "equipment": [{"name": "橡胶包胶杠铃片套装", "image": "http://localhost:9000/fitness-bucket/images/71d74753-bb23-4ac3-a041-6ca2dc51e2e4.webp"}, {"name": "史密斯训练架", "image": "http://localhost:9000/fitness-bucket/images/6b017543-142a-422b-8f38-0caa3137bce0.webp"}, {"name": "可调节哑铃套装", "image": "http://localhost:9000/fitness-bucket/images/960bcc89-c268-4913-985d-edd725ac7e7e.jpg"}], "exercises": [{"name": "坐姿推举", "reps": 4, "sets": 3, "restSeconds": 90}, {"name": "划船", "reps": 4, "sets": 3, "restSeconds": 120}, {"name": "弯举", "reps": 3, "sets": 3, "restSeconds": 90}]}, {"focus": "核心稳定性强化", "courses": [{"id": 90, "name": "普拉提核心床", "category": "瑜伽普拉提", "duration": 60, "coverImage": "https://images.unsplash.com/photo-1518310383802-640c2de311b2?w=800", "description": "借助核心床进行普拉提训练，是强化核心肌群的高效途径。通过器械独特的弹簧阻力与滑动床板设计，训练者能在动态不稳定中精准激活深层肌群。这不仅有助于塑造紧致身形，更能显著提升身体稳定性与协调性，让每一次伸展与发力都充满控制之美。"}, {"id": 104, "name": "脊柱侧弯矫正", "category": "康复体态", "duration": 50, "coverImage": "https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=800", "description": "借助科学系统的专业训练，针对性矫正脊柱侧弯问题。通过强化核心肌群与优化体态排列，有效改善脊柱生理曲度，帮助身体重获自然平衡与挺拔姿态，从而提升整体健康气质。"}], "dayName": "周三", "equipment": [{"name": "史密斯训练架", "image": "http://localhost:9000/fitness-bucket/images/6b017543-142a-422b-8f38-0caa3137bce0.webp"}, {"name": "泡沫轴", "image": "http://localhost:9000/fitness-bucket/images/4eda3da5-5023-457b-8076-e7020f52a711.webp"}], "exercises": []}, {"focus": "有氧耐力与心肺强化", "courses": [{"id": 88, "name": "有氧舞蹈派对", "category": "有氧燃脂", "duration": 50, "coverImage": "https://images.unsplash.com/photo-1524594152303-9fd13543fe6e?w=800", "description": "结合流行舞蹈的有氧运动，快乐燃脂不枯燥"}, {"id": 101, "name": "街舞Hip-Hop", "category": "舞蹈操课", "duration": 60, "coverImage": "https://images.unsplash.com/photo-1535525153412-5a42439a210d?w=800", "description": "学习Hip-Hop基础律动与舞步，释放青春活力"}], "dayName": "周四", "equipment": [{"name": "商用跑步机 X1", "image": "http://localhost:9000/fitness-bucket/images/2a4e805e-b137-47c5-be32-e3b3e005e00a.webp"}, {"name": "划船机 R300", "image": "http://localhost:9000/fitness-bucket/images/4ad04cff-064f-4920-9