0, "coverImage": "https://images.unsplash.com/photo-1534438327276-14e5300c3a48?w=800", "description": "以复合动作为核心构建力量循环训练，系统提升全身整体力量水平。"}, {"id": 76, "name": "杠铃深蹲特训", "category": "力量训练", "duration": 60, "coverImage": "https://images.unsplash.com/photo-1534367507873-d2d7e24c797f?w=800", "description": "系统掌握杠铃深蹲要领，强化下肢力量与核心稳定，提升运动表现与体态控制。"}], "dayName": "周五", "equipment": [{"name": "划船机 R300", "image": "http://localhost:9000/fitness-bucket/images/4ad04cff-064f-4920-9195-7a2c98267a00.webp"}, {"name": "腿举训练器", "image": "http://localhost:9000/fitness-bucket/images/5255958d-f107-45a6-8383-6d4904961526.webp"}], "exercises": [{"name": "硬拉", "reps": 4, "sets": 3, "restSeconds": 90}, {"name": "臀推", "reps": 3, "sets": 3, "restSeconds": 120}, {"name": "腿举", "reps": 4, "sets": 3, "restSeconds": 90}]}, {"focus": "功能性训练与灵活性", "courses": [{"id": 104, "name": "脊柱侧弯矫正", "category": "康复体态", "duration": 50, "coverImage": "https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=800", "description": "借助科学系统的专业训练，针对性矫正脊柱侧弯问题。通过强化核心肌群与优化体态排列，有效改善脊柱生理曲度，帮助身体重获自然平衡与挺拔姿态，从而提升整体健康气质。"}, {"id": 99, "name": "Zumba尊巴舞", "category": "舞蹈操课", "duration": 50, "coverImage": "http://localhost:9000/fitness-bucket/courses/50e9109f-1dbd-476f-b23c-02d9d8266994.jpg", "description": "拉丁风格有氧舞蹈，热情奔放，以律动与节奏燃脂塑形，融合踢踏、摇摆与旋转，提升心肺耐力与核心控制。"}], "dayName": "周六", "equipment": [{"name": "龙门架综合训练器", "image": "http://localhost:9000/fitness-bucket/images/a29ba2e2-f49c-4340-b090-38a2ad3a3776.webp"}, {"name": "弹力带套装", "image": "http://localhost:9000/fitness-bucket/images/4800b936-589d-4380-8b88-19cd1eb0ac16.jpg"}], "exercises": []}, {"focus": "深度放松与恢复", "courses": null, "dayName": "周日", "equipment": [], "exercises": []}]}');
