INSERT INTO public.fitness_plan (id, user_id, plan_name, goal, duration, status, deleted, create_time, update_time, level, height, weight, age, gender, experience, fitness_goal, plan_data_json) VALUES (71, 40, '大体重初级减脂专属7天温和启动计划', NULL, NULL, 1, false, '2026-05-08 20:30:07.993811', '2026-05-08 20:30:07.993811', NULL, 188.00, 130.00, 17, 'MALE', '初级', '减脂', '{"subtitle": "大体重初级减脂专属7天温和启动计划", "userInfo": {"bmi": "36.8", "goal": "减脂", "height": "188 cm", "weight": "130 kg", "intensity": "初级"}, "weeklyPlan": [{"focus": "有氧燃脂", "courses": [{"id": 88, "name": "有氧舞蹈派对", "category": "有氧燃脂", "duration": 50, "coverImage": "https://images.unsplash.com/photo-1524594152303-9fd13543fe6e?w=800", "description": "结合流行舞蹈的有氧运动，快乐燃脂不枯燥"}, {"id": 102, "name": "民族健身操", "category": "舞蹈操课", "duration": 65, "coverImage": "http://localhost:9000/fitness-bucket/courses/cdce174a-912b-403a-8f12-e0b7977098da.jpg", "description": "本套健身操创新融合了民族舞蹈的艺术精髓，将传统舞姿的柔美韵律与现代健身的科学节奏完美结合。在律动中，不仅能有效提升心肺功能、强健体魄，更能陶冶情操、展现优雅体态。它打破了传统健身的枯燥，实现了健康体魄与艺术修养的双重提升，让每一次跃动都成为一场身心合一的悦动体验。"}], "dayName": "周一", "equipment": [{"name": "椭圆机 E500", "image": "http://localhost:9000/fitness-bucket/images/e07bbab0-9357-4271-952a-ca20621624b3.webp"}, {"name": "弹力带套装", "image": "http://localhost:9000/fitness-bucket/images/4800b936-589d-4380-8b88-19cd1eb0ac16.jpg"}], "exercises": [{"name": "椭圆机慢跑", "reps": 30, "sets": 1, "restSeconds": 60}, {"name": "弹力带站姿推胸", "reps": 12, "sets": 3, "restSeconds": 60}, {"name": "弹力带深蹲", "reps": 15, "sets": 3, "restSeconds": 60}, {"name": "站姿提踵", "reps": 20, "sets": 3, "restSeconds": 45}, {"name": "弹力带高位下拉", "reps": 12, "sets": 3, "restSeconds": 60}, {"name": "原地高抬腿走", "reps": 30, "sets": 3, "restSeconds": 45}]}, {"focus": "力量训练", "courses": [{"id": 81, "name": "全身力量循环", "category": "力量训练", "duration": 90, "coverImage": "https://images.unsplash.com/photo-1534438327276-14e5300c3a48?w=800", "description": "以复合动作为核心构建力量循环训练，系统提升全身整体力量水平。"}, {"id": 79, "name": "肩部塑形训练", "category": "力量训练", "duration": 45, "c