"sets": 3, "restSeconds": 60}, {"name": "站姿腹部呼吸收缩", "reps": 20, "sets": 3, "restSeconds": 30}]}, {"focus": "康复体态", "courses": [{"id": 104, "name": "脊柱侧弯矫正", "category": "康复体态", "duration": 50, "coverImage": "https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=800", "description": "借助科学系统的专业训练，针对性矫正脊柱侧弯问题。通过强化核心肌群与优化体态排列，有效改善脊柱生理曲度，帮助身体重获自然平衡与挺拔姿态，从而提升整体健康气质。"}, {"id": 93, "name": "垫上普拉提塑形", "category": "瑜伽普拉提", "duration": 50, "coverImage": "https://images.unsplash.com/photo-1575052814086-f385e2e2ad1b?w=800", "description": "经典垫上普拉提动作，塑造修长线条与优雅体态"}], "dayName": "周四", "equipment": [{"name": "泡沫轴", "image": "http://localhost:9000/fitness-bucket/images/4eda3da5-5023-457b-8076-e7020f52a711.webp"}, {"name": "弹力带套装", "image": "http://localhost:9000/fitness-bucket/images/4800b936-589d-4380-8b88-19cd1eb0ac16.jpg"}], "exercises": [{"name": "泡沫轴背部放松", "reps": 10, "sets": 1, "restSeconds": 30}, {"name": "泡沫轴大腿前侧放松", "reps": 10, "sets": 1, "restSeconds": 30}, {"name": "猫牛式脊柱伸展", "reps": 15, "sets": 3, "restSeconds": 30}, {"name": "死虫式核心激活", "reps": 12, "sets": 3, "restSeconds": 45}, {"name": "弹力带面拉", "reps": 15, "sets": 3, "restSeconds": 45}, {"name": "鸟狗式核心稳定", "reps": 10, "sets": 3, "restSeconds": 45}]}, {"focus": "力量训练", "courses": [{"id": 80, "name": "手臂力量轰炸", "category": "力量训练", "duration": 40, "coverImage": "http://localhost:9000/fitness-bucket/courses/589bd94f-3ee4-4cd0-9896-528bcd2d2930.webp", "description": "二头肌与三头肌超级组训练，突破臂围瓶颈，高效刺激双臂肌群，提升力量与耐力。"}, {"id": 76, "name": "杠铃深蹲特训", "category": "力量训练", "duration": 60, "coverImage": "https://images.unsplash.com/photo-1534367507873-d2d7e24c797f?w=800", "description": "系统掌握杠铃深蹲要领，强化下肢力量与核心稳定，提升运动表现与体态控制。"}], "dayName": "周五", "equipment": [{"name": "奥林匹克杠铃杆", "image": "http://localhost:9000/fitness-bucket/images/89f93cc1-0835-4764-9680-fe7e28a83c46.webp"}, {"name": "腿举训练器", "image": "http://localhost:9000/fitness-bucket/images/5255958d-f107-45a6-8383-6d4904961526.webp"}, {"name": "坐姿划船器", "image": "http://localhost:9000/fitness-bucket/images/b93bee2e-a720-48c0-8fa4-05439f075f7a.webp"}], "exercises": [{"name": "空杆深蹲", "reps": 12, "sets": 3, "restSeconds": 90}, {"name": "器械腿举", "reps": 12, "sets": 3, "restSeconds": 90}, {"name": "器械坐姿划船", "reps": 12, "sets": 3, "restSeconds": 60}, {"name": "龙门架二头肌弯举", "reps": 12, "sets": 3, "restSeconds": 60}, {"name": "龙门架三头肌下压", "reps": 12, "sets": 3, "restSeconds": 60}, {"name": "壶铃摇摆", "reps": 15, "sets": 3, "restSeconds": 60}]}, {"focus": "有氧燃脂", "courses": [{"id": 99, "name": "Zumba尊巴舞", "category": "舞蹈操课", "duration": 50, "coverImage": "http://localhost:9000/fitness-bucket/courses/50e9109f-1dbd-476f-b23c-02d9d8266994.jpg", "description": "拉丁风格有氧舞蹈，热情奔放，以律动与节奏燃脂塑形，融合踢踏、摇摆与旋转，提升心肺耐力与核心控制。"}, {"id": 84, "name": "跳绳燃脂课", "category": "有氧燃脂", "duration": 45, "coverImage": "http://localhost:9000/fitness-bucket/courses/41873e51-e76b-44ae-9cad-9bc787845fb3.webp", "description": "高强度跳绳训练，快速提升心率，高效燃烧卡路里。"}], "dayName": "周六", "equipment": [{"name": "椭圆机 E500", "image": "http://localhost:9000/fitness-bucket/images/e07bbab0-9357-4271-952a-ca20621624b3.webp"}, {"name": "TRX悬挂训练带", "image": null}], "exercises": [{"name": "椭圆机对侧交替发力", "reps": 25, "sets": 1, "restSeconds": 60}, {"name": "无绳模拟跳绳", "reps": 60, "sets": 3, "restSeconds": 45}, {"name": "TRX深蹲", "reps": 15, "sets": 3, "restSeconds": 60}, {"name": "TRX划船", "reps": 12, "sets": 3, "restSeconds": 60}, {"name": "徒手侧向滑步", "reps": 20, "sets": 3, "restSeconds": 45}, {"name": "坐姿卷腹", "reps": 15, "sets": 3, "restSeconds": 45}]}, {"focus": "休息日", "courses": null, "dayName": "周日", "equipment": [], "exercises": []}]}');
