INSERT INTO public.knowledge_chunk (id, document_id, chunk_index, content, content_hash, embedding, metadata, char_count, create_time) VALUES (149, 12, 2, '## 如何选择教练

### 根据健身目标选择

* **减脂塑形**：推荐张磊教练、李娜教练
* **增肌增重**：推荐张磊教练
* **体态调整**：推荐张磊教练、王强教练
* **康复训练**：推荐王强教练
* **产后恢复**：推荐李娜教练
* **团课训练**：推荐刘芳教练

### 根据时间安排选择

* **上午时段**：李娜教练（9:00-18:00）、刘芳教练
* **下午时段**：张磊教练（10:00-20:00）、王强教练（14:00-22:00）
* **晚间时段**：张磊教练、王强教练、刘芳教练

