INSERT INTO public.knowledge_chunk (id, document_id, chunk_index, content, content_hash, embedding, metadata, char_count, create_time) VALUES (133, 10, 3, '## 禁止事项

1. 禁止在场馆内吸烟、饮酒、进食有异味的食物
2. 禁止大声喧哗、播放大音量音乐，影响其他会员
3. 禁止在非指定区域拍照、录像，如需拍照请提前告知前台，且禁止拍摄其他会员
4. 禁止带宠物入场
5. 禁止将非会员带入场馆蹭练，一经发现，暂停会员权限 1 周
6. 禁止在场馆内进行商业推广、发传单等行为

