INSERT INTO public.knowledge_chunk (id, document_id, chunk_index, content, content_hash, embedding, metadata, char_count, create_time) VALUES (139, 11, 3, '## 其他问题

### Q：怎么开发票？

**A**：您可以在前台办理，提供开票信息，我们会为您开具增值税普通发票，开票金额为您实际支付的金额。也可以在公众号提交开票申请，我们会将电子发票发送到您的邮箱。

### Q：我在健身的时候受伤了怎么办？

**A**：如果您在健身过程中受伤，请立即停止训练，联系附近的教练或前台，我们有专业的急救人员与设备，可进行紧急处理。如情况严重，我们会协助您送往附近医院。

### Q：场馆可以停车吗？

**A**：场馆所在的现代城有地下停车场，会员健身可领取停车券，前 3 小时免费，超过部分按 5 元 / 小时收费。

### Q：我可以在场馆里吃蛋白粉吗？

**A**：可以的，您可以在休息区饮用补剂，但是请勿在器械区进食，避免弄脏器械。

### Q：场馆有 WiFi 吗？

**A**：有的，场馆提供免费 WiFi，账号和密码可在前台或场馆内公告栏查看。

### Q：可以带小孩来健身吗？

**A**：16 周岁以下未成年人需由监护人陪同入场，且禁止独自使用力量器械。我们建议家长为孩子选择我们的儿童体适能课程。', '9fceef31f2dabb283baad71ebf118f54', '[0.01485265,-0.026434442,-0.0058374936,-0.013803461,-0.046947367,0.021234244,-0.015039527,0.05727406,0.020838827,-0.060462404,-0.014256945,-0.04355731,0.016359214,0.0068814587,0.06743162,0.057627633,0.017447144,0.06558369,-0.0883539,0.029121688,-0.07507511,0.012038451,0.086148344,0.0011271021,-0.012245565,0.08025468,0.02091959,0.057571784,-0.011232931,0.01581542,0.020353789,0.009463508,0.018634306,0.020249024,0.05204297,0.0005690749,-0.007014131,-0.004810943,0.075598046,-0.0071973274,0.01947403,0.07528351,-0.007379373,-0.014036284,0.03343893,-0.021681102,0.016728235,0.008320597,0.0179436,-0.014559643,-0.017549548,0.019276833,-0.034450084,0.06564567,-0.05739161,0.013696546,-0.0107554,0.020448266,-0.002350001,0.035412095,-0.03474658,-0.030867783,0.022907926,0.057602707,-0.015736949,-0.04258114,-0.040718257,0.018420726,0.008486684,0.08717379,-0.025549069,-0.051420946,0.013138086,0.0013406079,0.1305613,0.014383771,-0.03352432,-0.04335635,0.012256104,-0.03760624,0.0024051834,-0.08484639,-0.0008835443,-0.0071200025,0.030038008,0.00894984,-0.025525035,-0.037354827,0.052199952,0.018533055,-0.009853721,-0.07930879,0.02256343,-0.009844555,0.008601274,0.0045700585,-0.01254253,0.057482325,0.0029884756,-0.0329504,-0.02725094,-0.014753376,0.00029801455,0.055379387,0.002592372,0.029959016,0.013966192,0.012226742,0.023844894,0.017483698,-0.03245059,-0.014827659,0.019440057,-0.033275433,-0.005012684,0.014984595,-0.06227123,0.03373831,0.024356784,-0.059019193,0.005590712,0.052491352,0.032541905,-0.0051659117,0.012614456,0.015360596,0.027086344,-0.036764737,0.0015318235,-0.030022683,-0.0018936882,-0.03581023,0.017414158,0.025958799,-0.00969827,0.041754015,-0.0036824588,-0.017584506,0.049625583,-0.0005441512,-0.02597097,-0.04423861,0.022502262,-0.0025624367,-0.03231698,0.08701803,0.018163376,-0.0030528768,0.05901301,0.07257386,0.08620164,-0.033285346,-0.007996744,-0.038740315,-0.0119966