INSERT INTO public.sys_announcement (id, title, content, type, status, view_count, publish_time, deleted, create_time, update_time) VALUES (1, '内容测试', '放假时间xxx-xxxx', 'SYSTEM', 0, 0, '2026-03-28 14:10:06.269343', false, '2026-03-28 14:10:05.2151', '2026-03-28 14:16:54.937894');
INSERT INTO public.sys_announcement (id, title, content, type, status, view_count, publish_time, deleted, create_time, update_time) VALUES (3, '春节营业时间调整通知', '尊敬的会员：春节期间（2025年1月28日-2月4日）营业时间调整为10:00-18:00，2月5日起恢复正常营业。祝您新春快乐，身体健康！', 'IMPORTANT', 1, 1256, '2025-01-15 10:00:00', false, '2025-01-15 09:00:00', '2025-01-15 10:00:00');
INSERT INTO public.sys_announcement (id, title, content, type, status, view_count, publish_time, deleted, create_time, update_time) VALUES (4, '新器械上线通知', '本月新增多台高端有氧器械，包括Technogym最新款跑步机、椭圆机等，现已全面投入使用，欢迎会员体验！', 'SYSTEM', 1, 892, '2025-01-10 14:30:00', false, '2025-01-10 14:00:00', '2025-01-10 14:30:00');
INSERT INTO public.sys_announcement (id, title, content, type, status, view_count, publish_time, deleted, create_time, update_time) VALUES (6, '会员积分兑换活动', '积分兑换商品8折优惠活动开始啦！即日起至3月31日，会员可使用积分兑换运动补剂、装备等商品，享受8折优惠，数量有限，先到先得！', 'ACTIVITY', 1, 567, '2025-03-20 09:00:00', false, '2025-03-20 08:00:00', '2025-03-20 09:00:00');
INSERT INTO public.sys_announcement (id, title, content, type, status, view_count, publish_time, deleted, create_time, update_time) VALUES (7, '春季减脂挑战赛', '春暖花开，正是减脂好时节！参加我们的21天减脂挑战赛，专业教练全程指导，更有丰厚奖品等你来拿！报名截止4月5日。', 'ACTIVITY', 1, 234, '2025-03-25 10:00:00', false, '2025-03-25 09:00:00', '2025-03-25 10:00:00');
INSERT INTO public.sys_announcement (id, title, content, type, status, view_count, publish_time, deleted, create_time, update_time) VALUES (9, '会员有效期顺延通知', '因门店设备维护升级（3月19日-3月23日暂停营业），所有会员有效期将自动顺延5天，给您带来不便敬请谅解。', 'IMPORTANT', 1, 1890, '2025-03-18 08:00:00', false, '2025-03-18 07:00:00', '2025-03-18 08:00:00');
INSERT INTO public.sys_announcement (id, title, content, type, status, view_count, publish_time, deleted, create_time, update_time) VALUES (10, '私教课程优惠活动', '限时优惠！购买私教课程满20节赠送2节，满30节赠送5节，活动仅限本月，详情请咨询前台或您的专属教练。', 'ACTIVITY', 1, 445, '2025-03-15 14:00:00', false, '2025-03-15 13:00:00', '2025-03-15 14:00:00');
INSERT INTO public.sys_announcement (id, title, content, type, status, view_count, publish_time, deleted, create_time, update_time) VALUES (2, '活动通知', '今天有xxxx活动，时间xxx-xxx', 'ACTIVITY', 0, 0, '2026-03-28 14:10:53.532877', false, '2026-03-28 14:10:53.535335', '2026-03-28 14:21:34.855678');
INSERT INTO public.sys_announcement (id, title, content, type, status, view_count, publish_time, deleted, create_time, update_time) VALUES (5, '系统维护通知', '为提供更优质的服务，我们将于本周日凌晨2:00-6:00进行系统维护，期间APP部分功能可能无法使用，请提前安排您的训练计划。', 'SYSTEM', 0, 0, NULL, true, '2025-03-28 16:00:00', '2026-04-02 18:13:20.926081');
INSERT INTO public.sys_announcement (id, title, content, type, status, view_count, publish_time, deleted, create_time, update_time) VALUES (8, '瑜伽课程升级', '我们的瑜伽课程全面升级，新增空中瑜伽、高温瑜伽等课程，由资深瑜伽导师授课，现已开放预约，欢迎体验！', 'ACTIVITY', 0, 0, NULL, true, '2025-03-28 15:00:00', '2026-04-02 18:13:23.279334');


